-- ============================================================
-- Automatically populate Statement of Applicability for ISO 27001
-- ============================================================
INSERT INTO statement_of_applicability (organization_id, control_id, applicable, implementation_status)
SELECT
  fc.organization_id,
  fc.id,
  true,
  'not_started'
FROM framework_controls fc
WHERE fc.organization_id = :org_id
  AND fc.framework = 'ISO27001'
ON CONFLICT DO NOTHING;
